code = """import json, pandas as pd

# Load business rows (may be stored as a json file path)
biz_src = var_call_IMKRvjuFAPxAnc9JVGHmuhW5
if isinstance(biz_src, str):
    with open(biz_src, 'r', encoding='utf-8') as f:
        biz = json.load(f)
else:
    biz = biz_src

rev = var_call_u1HJ2vSGArVVzR8sJETI7KVC

biz_df = pd.DataFrame(biz)
rev_df = pd.DataFrame(rev)

# Parse hours; stored as string representation of list or None
import ast, re

def parse_hours(x):
    if x is None:
        return None
    if isinstance(x, str):
        if x.strip().lower() == 'none':
            return None
        try:
            return ast.literal_eval(x)
        except Exception:
            return None
    return x

weekday_set = {"Monday","Tuesday","Wednesday","Thursday","Friday"}

def closes_after_6pm(hours_list):
    if not hours_list or not isinstance(hours_list, list):
        return False
    for item in hours_list:
        if not (isinstance(item, (list, tuple)) and len(item) >= 2):
            continue
        day, times = item[0], item[1]
        if day not in weekday_set:
            continue
        if not isinstance(times, str):
            continue
        t = times.strip()
        if t.lower() == 'closed':
            continue
        if 'Open 24 hours'.lower() in t.lower():
            return True
        # handle split hours like "Closes 12PM • Reopens 1PM" not present here; ignore
        # Parse end time after an en dash
        if '–' in t:
            end = t.split('–',1)[1].strip()
        elif '-' in t:
            end = t.split('-',1)[1].strip()
        else:
            continue
        m = re.match(r'^(\d{1,2})(?::(\d{2}))?\s*(AM|PM)$', end, flags=re.I)
        if not m:
            continue
        hh = int(m.group(1))
        mm = int(m.group(2) or 0)
        ampm = m.group(3).upper()
        if hh == 12:
            hh24 = 0 if ampm=='AM' else 12
        else:
            hh24 = hh + (12 if ampm=='PM' else 0)
        minutes = hh24*60 + mm
        if minutes > 18*60:
            return True
    return False

biz_df['hours_parsed'] = biz_df['hours'].apply(parse_hours)
biz_df['open_after_6_weekday'] = biz_df['hours_parsed'].apply(closes_after_6pm)

eligible = biz_df[biz_df['open_after_6_weekday']].copy()

# Join with avg rating
rev_df['avg_rating'] = rev_df['avg_rating'].astype(float)
eligible = eligible.merge(rev_df[['gmap_id','avg_rating']], on='gmap_id', how='inner')

# Top 5 by avg_rating desc
eligible = eligible.sort_values(['avg_rating','name'], ascending=[False, True]).head(5)

# Prepare hours as readable string

def hours_to_str(hl):
    if not hl:
        return None
    parts=[]
    for day, times in hl:
        parts.append(f"{day}: {times}")
    return "; ".join(parts)

out = []
for _, r in eligible.iterrows():
    out.append({
        'name': r['name'],
        'average_rating': round(float(r['avg_rating']), 4),
        'operating_hours': hours_to_str(r['hours_parsed'])
    })

print("__RESULT__:")
print(json.dumps(out, ensure_ascii=False))"""

